import { json } from "@sveltejs/kit";
async function GET({ request, params }) {
  const { name } = params;
  const headers = {
    "Access-Control-Allow-Origin": "*",
    // すべてのオリジンからのアクセスを許可
    "Access-Control-Allow-Methods": "GET, OPTIONS",
    "Access-Control-Allow-Headers": "Content-Type"
  };
  if (request.method === "OPTIONS") {
    return new Response(null, {
      status: 204,
      headers
    });
  }
  try {
    let response = await fetch(`https://oc-style.sugi2000.workers.dev/api/v1/style/${name}`);
    if (!response.ok) {
      throw new Error(`Failed to fetch style data`);
    }
    const result = await response.json();
    if (!result) {
      return new Response("Style data not found", {
        status: 404,
        headers
      });
    }
    return json(result, {
      headers
    });
  } catch (error) {
    console.error("Service binding error:", error);
    return json({ success: false, error: error.message }, {
      status: 500,
      headers
    });
  }
}
async function POST({ request, params }) {
  const { name } = params;
  const { body } = request;
  const { headers } = request;
  const corsHeaders = {
    "Access-Control-Allow-Origin": "*",
    // すべてのオリジンからのアクセスを許可
    "Access-Control-Allow-Methods": "POST, OPTIONS",
    "Access-Control-Allow-Headers": "Content-Type"
  };
  if (request.method === "OPTIONS") {
    return new Response(null, {
      status: 204,
      headers: corsHeaders
    });
  }
  try {
    const jsonData = await request.json();
    let response = await fetch(`https://oc-style.sugi2000.workers.dev/api/v1/style/${name}`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify(jsonData)
    });
    if (!response.ok) {
      throw new Error(`Failed to fetch style data: ${response.status}`);
    }
    const result = await response.json();
    if (!result) {
      return new Response("Style data not found", {
        status: 404,
        headers: corsHeaders
      });
    }
    return json(result, {
      headers: corsHeaders
    });
  } catch (error) {
    console.error("Service binding error:", error);
    return json({ success: false, error: error.message }, {
      status: 500,
      headers: corsHeaders
    });
  }
}
export {
  GET,
  POST
};
